SELECT EMP_NO
  FROM EMP
 WHERE EMP_NM    = #{name}
   AND EMP_EMAIL = #{email}
   AND EMP_STAT_CD != 'RESIGN'
   AND ACNT_ACT_YN = 'Y'

SELECT COUNT(*)
  FROM EMP
 WHERE EMP_NO    = #{empNo}
   AND EMP_NM    = #{name}
   AND EMP_EMAIL = #{email}

SELECT NVL(ACNT_ACT_YN, 'N')
  FROM EMP
 WHERE EMP_NO = #{empNo}
